import json
from pathlib import Path


DEFAULTS = {
    "api_prefix": "/api",
    "request_timeout": 5,
}


class SettingsStore:
    def __init__(self, path):
        self.path = Path(path)
        self.values = dict(DEFAULTS)
        self.reload()

    def reload(self):
        payload = json.loads(self.path.read_text(encoding="utf-8"))
        self.values.update(payload)
        self._validate()

    def _validate(self):
        prefix = self.values["api_prefix"]
        if not isinstance(prefix, str) or not prefix.startswith("/"):
            raise ValueError("api_prefix must start with /")
        timeout = self.values["request_timeout"]
        if not isinstance(timeout, int) or timeout <= 0:
            raise ValueError("request_timeout must be a positive integer")

    @property
    def api_prefix(self):
        return self.values["api_prefix"].rstrip("/")

    @property
    def request_timeout(self):
        return self.values["request_timeout"]

