from urllib.parse import quote


class EndpointBuilder:
    def __init__(self, api_prefix):
        self.api_prefix = api_prefix

    def build(self, resource):
        encoded = quote(resource.strip("/"), safe="/")
        return f"{self.api_prefix}/{encoded}"


class GatewayRuntime:
    def __init__(self, settings):
        self.settings = settings
        self._endpoints = EndpointBuilder(settings.api_prefix)

    def reload(self):
        self.settings.reload()

    def endpoint_for(self, resource):
        return self._endpoints.build(resource)

    @property
    def request_timeout(self):
        return self.settings.request_timeout
